INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('3','1','MacBook Air M3','macbook-air-m3','Gümüş\r\n\r\nYıldız Işığı\r\n\r\nUzay Grisi\r\n\r\nGece Yarısı\r\n\r\nÇip\r\nApple M3 çip\r\n\r\n4 adet performans çekirdeğine ve 4 adet verimlilik çekirdeğine sahip 8 çekirdekli CPU\r\n\r\n8 çekirdekli GPU, 10 çekirdekli GPU\r\n\r\nDonanım hızlandırmalı ışın izleme\r\n\r\n16 çekirdekli Neural Engine\r\n\r\n100 GBps bellek bant genişliği\r\n\r\nMedia Engine\r\n\r\nDonanım hızlandırmalı H.264, HEVC, ProRes ve ProRes RAW\r\n\r\nVideolar için kod çözme motoru\r\n\r\nVideo kodlama motoru\r\n\r\nProRes formatında kodlama ve kod çözme motoru\r\n\r\nAV1 kod çözme\r\n\r\nYapılandırma seçenekleri:\r\n\r\n8 çekirdekli CPU’ya ve 10 çekirdekli GPU’ya sahip M3 çip\r\n\r\nEkran\r\nLiquid Retina ekran\r\n\r\nIPS teknolojisine sahip 13.6 inç (diyagonal) LED arkadan aydınlatmalı ekran;1 İnç başına 224 piksel yoğunlukta 2560 x 1664 özgün çözünürlük\r\n\r\n500 nit parlaklık\r\n\r\nRenk\r\n\r\n1 milyar renk desteği\r\n\r\nGeniş renk yelpazesi (P3)\r\n\r\nTrue Tone teknolojisi\r\n\r\nBellek\r\n16 GB birleşik bellek\r\n\r\nYapılandırma seçenekleri\r\n\r\n24 GB\r\n\r\n8 GB birleşik bellek\r\n\r\nYapılandırma seçenekleri\r\n\r\n16 GB veya 24 GB\r\n\r\nPil ve Güç2\r\nApple TV uygulamasından 18 saate kadar film izleme\r\n\r\nKablosuz bağlantıyla 15 saate kadar internette gezinme\r\n\r\n52.6 watt-saatlik lityum polimer pil\r\n\r\n30 W USB-C Güç Adaptörü (8 çekirdekli GPU’ya sahip M2 ve M3 çipli modellerde sunulur)\r\n\r\n35 W Çift USB-C Bağlantı Noktalı Güç Adaptörü (10 çekirdekli GPU’ya ve 512 GB depolama alanına sahip M2 ve M3 çipli modellerde sunulur, 8 çekirdekli GPU’ya sahip M2 ve M3 çipli modellerde yapılandırma seçeneği olarak sunulur)\r\n\r\nUSB-C - MagSafe 3 Kablosu\r\n\r\n70 W USB-C Güç Adaptörü ile hızlı şarj özelliği\r\n\r\nDepolama3\r\n256 GB SSD\r\n\r\nYapılandırma seçenekleri\r\n\r\n512 GB, 1 TB veya 2 TB','67999.00','64999.00','5',NULL,'products/bFi7XvN2TGED4qVlZeQTGjvdpTJJpOuF1YXkcpUq.png','0','1','2026-06-08 21:19:35','2026-06-09 14:32:38');
INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('4','1','APPLE Airpods 4 Bluetooth Kulak İçi Kulaklık MXP63TU/A','apple-airpods-4-bluetooth-kulak-ici-kulaklik-mxp63tua','Apple AirPods 4 bluetooth kulaklık, geniş kullanım alanıyla müzikseverler ve teknoloji meraklıları için ideal bir seçimdir. Uzun pil ömrüyle saatlerce kullanabilir, harika bir ses deneyimi yaşayabilirsiniz.\r\n\r\nKablosuz Kullanım Özgürlüğünü Yaşayın\r\nKablosuz sinyal iletimi teknolojisi sayesinde kablo karmaşasından tamamen kurtulabilirsiniz. Spor yaparken, işe giderken veya günlük aktivitelerinizi gerçekleştirirken hareket özgürlüğü elde edebilirsiniz.\r\n\r\nHızlı ve Stabil Bağlantı Sunan Bluetooth 5.3\r\nBluetooth 5.3 teknolojisi ile donatılmış olan AirPods 4 kablosuz kulaklık, son derece stabil ve hızlı bağlantı performansı sergiler. Bu sayede akıllı telefon, tablet veya bilgisayarınızla kolayca eşleştirebilirsiniz.\r\n\r\nBluetooth 5.3\'ün sunduğu optimize edilmiş veri aktarım hızı, yüksek kaliteli ses kodlamasını destekleyerek müzik dinleme deneyiminizi zenginleştirir. Gelişmiş bağlantı protokolü sayesinde 10 metreye kadar kesintisiz sinyal alımı gerçekleştirebilirsiniz. Düşük gecikme özelliği ile video izlerken veya oyun oynarken ses-görüntü uyumsuzluğu problemini ortadan kaldırabilirsiniz.\r\n\r\nEntegre Mikrofon Sayesinde Muhteşem Kalitede Ses İletimi\r\nDahili mikrofon özelliği ile telefon görüşmelerinizi net bir ses kalitesiyle gerçekleştirebilirsiniz. Eller serbest konuşma imkanı sunan bu sistem, iş görüşmelerinde ve kişisel aramalarında profesyonel ses kalitesi sağlar. Mikrofon teknolojisi, çevresel sesleri filtreleyerek karşı tarafın sizi net bir şekilde duymasını garanti eder. Video konferanslarda, online toplantılarda ve günlük telefon görüşmelerinde mükemmel performans gösterir ve iletişim kalitenizi artırır.\r\n\r\n30 Saate Varan Pil Ömrü\r\nAirPods 4\'ün 30 saate kadar uzanan maksimum batarya süresi ile günlük kullanımınızı kesintisiz sürdürebilirsiniz. Bu uzun pil ömrü sayesinde sık şarj etme ihtiyacı duymadan saatlerce müzik dinleme keyfini yaşarsınız. Uzun seyahatlerde, iş günlerinde ve hafta sonu aktivitelerinde güvenle kullanabilirsiniz.\r\n\r\nEnerji verimli tasarım anlayışı, batarya ömrünü uzatırken çevresel etkiyi de minimize eder. Akıllı güç yönetim sistemi, kullanım alışkanlıklarınıza göre enerji tüketimini ayarlayarak optimal performans sergiler.','6570.00','5900.00','20',NULL,'products/pm8PVicp4X4JSsExU0EJp3FRKEp3xjTjPEWllRkl.jpg','0','1','2026-06-08 21:19:35','2026-06-09 14:20:44');
