INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('16','6','Miss Dior - Parfum 50ml','miss-dior-parfum-50ml','Miss Dior, Provence\'da ateş böceklerinin aydınlattığı, yeşil yaseminin gece ve toprağın melodisiyle ahenk oluşturduğu akşamlardan doğdu.” Christian Dior, 1947 yılında ilk kokusu Miss Dior\'u yaratmasının ardındaki ilhamı işte böyle tanımlıyor.\r\n\r\nFrancis Kurkdjian\'ın orijinal Miss Dior\'u yeniden yorumlayışı: Miss Dior Parfum. Yaseminin hâkim olduğu ve amberimsi ağaç akorlarıyla sarılı, mandalina notalarıyla aşılanmış nadir, meyvemsi yönleri olan yoğun bir kadın kokusu. Sulu meyveler ve kır çiçekleriyle dolu, yosun kaplı bir ormanda gece gezintisinin kokusal tercümesi.\r\n\r\nMiss Dior\'un simgesi olan kaz ayağı motifi şişeyi çevreliyor. Boyuna bağlanan gümüşi bir \'poignard\' fiyonk, Miss Dior Parfum\'ün imza niteliğindeki couture ruhunu tamamlıyor.\r\nÜrün kodu\r\n\r\n720056\r\n\r\nÜretici iletişim:\r\n\r\nAB sorumlusu iletişim','7149.98',NULL,'30',NULL,'products/AulbdZnfOadJiYamMJk7Z68YbZDyxHtFnl1QIARn.jpg','0','1','2026-06-08 21:43:44','2026-06-09 14:31:18');
INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('17','6','Dior Sauvage - Eau de Parfum','dior-sauvage-eau-de-parfum','Sauvage\'ın güçlü tazeliği, yeni duygusal ve gizemli yönlerini ortaya çıkarıyor. Sulu Bergamot, duyusallığı arttırmak için baharatlı notaları davet ediyor; Ambroksan ve Papua Yeni Gine Vanilya aromasıyla etrafı sarılıyor. Dior Parfüm Yaratıcısı, François Demachy, ilhamını çöl alacakaranlığının büyülü saatinden alıyor. Gecenin soğuğu çölün yakıcılığıyla bu eşsiz kokuda buluşuyor.\r\nÜrün kodu\r\n\r\n421404\r\n\r\nÜretici iletişim:\r\n\r\nAB sorumlusu iletişim:','5870.00',NULL,'10',NULL,'products/zPQhi6FuAZ1RkuAKuiSiasdikttVN1gKxCvpk5o2.jpg','0','1','2026-06-08 21:45:54','2026-06-09 14:29:41');
