INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('22','8','Black Stone Tencere Seti 7 Parça - Schafer','black-stone-tencere-seti-7-parca-schafer','Schafer Black Stone Tencere Seti 7 Parça-Siyah\r\n\r\nBlack Stone 7 Parça Tencere Seti, mutfakta hem fonksiyonelliği hem de estetik şıklığı bir arada sunar. Taş dokulu granit görünümlü yüzeyi ve dayanıklı yapısıyla günlük kullanıma uygundur. Farklı boyutlardaki tencereler, tava ve karnıyarık tenceresi ile çeşitli pişirme ihtiyaçlarını karşılar. Geniş iç hacmi, yapışmaz yüzeyi ve modern tasarımıyla Black Stone Set, her mutfağın vazgeçilmez yardımcısıdır.\r\n\r\nSet İçeriği\r\n•  18 cm Derin Tencere + Kapak – 2 Litre\r\n•  22 cm Derin Tencere + Kapak – 3 Litre\r\n•  26 cm Karnıyarık Tenceresi + Kapak – 3,5 Litre\r\n•  26 cm Tava\r\n\r\nTeknik Özellikler\r\n•  Malzeme: Alüminyum döküm üzerine güçlendirilmiş granit kaplama\r\n•  Kaplama: Yapışmaz ve çizilmeye karşı dayanıklı granit görünümlü yüzey\r\n•  Renk: Siyah taş dokulu dış yüzey\r\n•  Kapak: Isıya dayanıklı cam kapaklar\r\n•  Kulplar: El yakmayan ergonomik bakalit kulplar\r\n•  Uyum: Gazlı ve elektrikli ocaklarla uyumlu (indüksiyon hariç)\r\n•  Kullanım Alanı: Kızartma, haşlama, soteleme, tencere yemekleri ve daha fazlası\r\n\r\nKullanım Talimatı\r\n•  İlk kullanım öncesi ürünleri ılık sabunlu su ile yıkayınız ve kurulayınız.\r\n•  Orta ateşte kullanım önerilir; yüksek ısıda boş ısıtmayınız.\r\n•  Yüzeyin korunması için sadece plastik, silikon veya ahşap gereçler kullanınız.\r\n•  Ani sıcaklık değişimlerinden kaçınınız.\r\n•  Bulaşık makinesinde yıkanabilir; ancak kaplamanın ömrünü uzatmak için elde yıkama tavsiye edilir.\r\n•  Sert sünger veya aşındırıcı temizlik ürünleri kullanmayınız.','3799.00','2499.00','18',NULL,'products/fggv54t8pyjvj9uQLbb4Gwv0ijuYMplo9vUEvzWk.jpg','1','1','2026-06-08 21:57:13','2026-06-09 14:33:16');
INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('23','3','Fenerbahçe Dekomus Gıft Box Özel Kutulu Sarı Kanarya Kırtasiye Seti Uçlu Kalemi Roket Silgi,Airpods','fenerbahce-dekomus-gift-box-ozel-kutulu-sari-kanarya-kirtasiye-seti-uclu-kalemi-roket-silgiairpods','ÖZELLİKLİ KUTULU SET: Fenerbahçe resmi lisanslı ürün, sarı kanarya temalı dekoratif hediye kutusunda sunulan eksiksiz kırtasiye seti\r\nKOMPLİT KIRTASİYE ÇÖZÜMÜ: Uçlu kalem, roket silgi ve AirPods ile birlikte gelen pratik ve şık kombinasyon\r\nYAZIM ARACI: Kaliteli uçlu kalem, günlük yazı işlemleri ve not alma için ideal\r\nBONUS AKSESUARLAR: Roket silgi ve AirPods ile ekstra değer sağlayan kapsamlı set\r\nHEDİYE HAZIR PAKETLEME: Özel kutulu sunumu sayesinde doğrudan hediye olarak verilebilecek şekilde hazırlanmış','909.00',NULL,'35',NULL,'products/Q5YbHNNMF18hM57YGpNl0p1NRPVUlbN0FBMT55PR.webp','0','1','2026-06-08 21:57:13','2026-06-09 14:22:06');
