INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('25','5','Temiz Kod - M. Furkan Ardoğan','temiz-kod-m-furkan-ardogan','Belki bir evi herkes inşa edebilir fakat gökdelen inşa etmek aynı değildir. Daha ciddi işler çıkarmanın daha hazırlıklı ve teknik olmayı gerektirmek gibi zorlu bir yönü vardır. Peki, daha ciddi yazılımlar geliştirmek istediğinizde aklınızda olması gerekenler hakkında ne biliyorsunuz? İyi yazılmış kodlar tesadüf değildir ve daha iyi kodlar yazmak kullandığınız programlama dilinin de çok ötesindedir. Yeni kodlar yazarken göz önünde bulundurmanız gereken prensipler, izleyebileceğiniz tasarım kalıpları, daha başarılı birim testleri yazmak için yapabilecekleriniz, var olan kodlardaki problemleri tespit edip onları ekarte etmek için uygulayabileceğiniz birçok yöntem ve daha fazlası.\r\nBu kitap, Nesne Yönelimli Programlama dilleriyle uygulama geliştiren herkes için. Eğer bir miktar programlama geçmişiniz varsa (programlama geçmişinizin olduğu varsayılacaktır) ve daha güçlü, esnek nesne yönelimli tasarımlar yapabilmek konusunda hevesliyseniz bu kitap tam size göre diyebiliriz.\r\n\r\n• Nesne Yönelimli Analiz ve Tasarım\r\n• Coupling & Amp; Decoupling\r\n• Inversion of Control & Dependency Injection\r\n• UML ile Modelleme (Class & Package & Sequence Diyagramları)\r\n• Kodlama Prensipleri (SOLID, Granularity vb.)\r\n• GoF Tasarım Kalıpları\r\n• Code Smells & Refactoring Yöntemleri\r\n• Test Yazma Prensipleri & Tasarım Kalıpları\r\n• Test Driven Development\r\n• CQR\r\nKitap Adı:\r\nTemiz Kod\r\nYazar:\r\nM. Furkan Ardoğan\r\nYayınevi:\r\nKodlab\r\nHamur Tipi:\r\n2. Hamur\r\nSayfa Sayısı:\r\n568\r\nEbat:\r\n15 x 21\r\nİlk Baskı Yılı:\r\n2023\r\nBaskı Sayısı:\r\n1. Basım\r\nDil:\r\nTürkçe\r\nBarkod:\r\n9786257440646','399.00','349.00','45',NULL,'products/QhTVb7P1pvH0f8xo7LpbyfFk9wpb3xFKDPkvA0qs.png','0','1','2026-06-08 21:57:13','2026-06-09 14:29:13');
INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('26','1','Dell Tower ECT1250 I5-14400 16GB 512GB SSD Ubuntu ECT1250-RPLS-R-003-U','dell-tower-ect1250-i5-14400-16gb-512gb-ssd-ubuntu-ect1250-rpls-r-003-u','Boyutlar ve ağırlık\r\n1. Yükseklik: 12,76 inç (324,3 mm)\r\n2. Genişlik: 6,06 inç (154 mm)\r\n3. Genişlik: 6,06 inç (154 mm)\r\nBaşlangıç ağırlığı: 9,17 lb. (4,16 kg)','37630.12',NULL,'0',NULL,'products/lJCvKbCpemA8yPFz74iWi7bDgmmEhLYUR8LL3qag.jpg','0','1','2026-06-09 10:43:46','2026-06-09 14:21:11');
INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('27','1','DELL Pro 14 Notebook U5 16/512 FDOS','dell-pro-14-notebook-u5-16512-fdos','Dell Pro 14 Dizüstü Bilgisayar Serisi\r\nYeni, modern bir tasarımda temel üretkenlik\r\nGelişmiş mobilite ve performans, uzun pil ömrü ve tamamen yeni yenilikçi tasarım, bu cihazı güvenebileceğiniz bir cihaz haline getiriyor. Dell Pro dizüstü bilgisayarlar %30’a kadar PCR plastik ile tasarlanmıştır\r\n\r\nDaha şık, daha hafif ve daha akıcı çalışın\r\nDell Pro 14, platin gümüş renginde şık metalik kaplamaya ve manyetit renginde dokulu kaplamaya sahiptir.\r\n\r\nİşiniz sizi nereye götürürse götürsün seyahat etmek için tasarlanan Dell Pro 14, dayanıklılık ve güvenilirlik açısından zorlu MIL–STD testlerinden geçer.\r\n\r\nWindows‘ta Copilot‘un yardımıyla, Windows Copilot tuşunu kullanarak kendi kişisel yapay zeka asistanınıza anında erişebilirsiniz. Wi–Fi 7‘ye kadar hızlı bağlantı seçenekleriyle her yerden üretkenliğinizi koruyabilirsiniz.\r\n\r\nDaha dar çerçevelere ve aynı alanda %10 daha hafif bir alanda %5 daha fazla ekran alanına sahip geniş 16:10 ekran sayesinde, daha geniş, daha ayrıntılı bir ekranda daha verimli çalışabilirsiniz.\r\n\r\nDaha akıllı çalışın\r\nNPU, GPU ve CPU’ya sahip isteğe bağlı Intel® Core™ Ultra 200U serisi işlemcilerle olağanüstü performans, pil ömrü ve güçlü cihaz içi yapay zekadan yararlanın.Intel vPro® Platformu ile BT departmanları, işlerini desteklemek için gereken çok katmanlı güvenliği, uzaktan yönetilebilirliği ve güvenilir kararlılığı elde eder.\r\n\r\nNPU – Düşük Güç: Görüntülü aramalar sırasında Microsoft Studio Efektleri gibi yapay zeka özelliklerini çalıştırmak için idealdir. \r\nCPU – Hızlı Yanıt: Gerçek zamanlı çoklu görev ve gürültü engelleme ve anında transkripsiyon gibi yapay zeka iş yükleri için idealdir.\r\nGPU – Yüksek Verim: Yapay zeka hızlandırmalı dijital içerik oluşturma ve video düzenleme için idealdir.','67000.00',NULL,'10',NULL,'products/flXf1dQ9fpGCnq6EQHlS9FtlwCi8K108PZJ1NzTv.jpg','0','1','2026-06-09 10:46:46','2026-06-09 14:20:58');
