INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('29','5','Yeraltından Notlar','yeraltindan-notlar','Ürün Açıklaması\r\nFyodor Mihayloviç Dostoyevski (1821-1881 ): İlk roman İnsancıklar\'ın çarpıcı konusu ve farklı kurgusuyla dikkatleri çekti.\r\n\r\nİnsan ruhunun derinliklerini sergileyiş gücüyle önemli bir yazar olarak ün kazandı.\r\n\r\nAncak daha sonra yayımlanan eseri o dönemde fazla ilgi görmedi.\r\n\r\nDostoyevski 1849\'da 1.Nikolay\'ın baskıcı rejimine muhalif Petraşevski grubunu üyesi olduğu gerekçesiyle tutuklandı.\r\n\r\nKurşuna dizilmek üzereyken cezası sürgün ve zorunlu askerliğe çevrildi.\r\n\r\nSibirya sürgününden sonra yazdığı romanlarla tekrar eski ününe kavuştu.1864\'de Vremya dergisinde yayımladığı Yeraltından Notlar gerçek dünyadan kendini soyutlamış bir kişinin iç çatışmalarını ve hezeyanlarını konu alır.\r\n\r\nBu roman Dostoyevski\'nin daha sonra yazacağı büyük romanların ipuçlarını taşımaktadır.\r\n\r\nÜrün Adı: Yeraltından Notlar - Hasan Ali Yücel Klasikleri Ürün Kodu: 9789944884013 Yazar: Fyodor Mihayloviç Dostoyevski Basım Yılı: 2020 Kapak Türü: Karton Kapak Sayfa Sayısı: 140 Kağıt Cinsi: 2. Hamur Çevirmen: Nihal Yalaza Taluy','85.00',NULL,'0',NULL,'products/l0x2Tj2Gb85fWaDjshNwxq7Jvqi6TtfywX28AaRq.jpg','0','1','2026-06-09 10:52:22','2026-06-09 14:29:26');
INSERT INTO `products` (`id`,`category_id`,`name`,`slug`,`description`,`price`,`discount_price`,`stock`,`sizes`,`image`,`featured`,`status`,`created_at`,`updated_at`) VALUES ('30','2','Nike Moon Shoe OG','nike-moon-shoe-og','Bu ürün site promosyonları ve indirimleri kapsamında değildir.\r\nNike henüz Nike adını almadan önce Bill Bowerman, eşinin waffle ızgarasını kullanarak şirketin ilk koşu ayakkabısını yaratmıştı. Modern yorumuyla bu model, orijinal tasarımı yeniden ilgi odağı haline getiriyor. Deri detaylar ve Swoosh logoları ile tamamlanan naylon üst kısım, 1970\'lerin koşucu stilini yeniden yaratmak için Waffle tabanla bir araya geliyor. Efsaneyi başlatan ayakkabıyla tarihte bir yolculuğa çık.\r\n\r\n\r\nGösterilen Renk: Soft Yellow/Siyah/Soft Pearl\r\nStil: IW0955-700\r\nMenşe Ülke/Bölge: Vietnam','5499.00',NULL,'0',NULL,'products/9P6geq9e5IunTpbvz9pMKiiUUteJHdfagwuevYg6.png','0','1','2026-06-09 14:27:52','2026-06-09 14:28:46');
